// src/components/PropertyList.js
import React from 'react';

const PropertyList = ({ properties = [], loading = false, error = null, onSelect }) => {
  if (loading) {
    return <div data-testid="loading">Loading...</div>;
  }

  if (error) {
    return <div data-testid="error">{error}</div>;
  }

  if (properties.length === 0) {
    return <div data-testid="empty-list">No properties found.</div>;
  }

  return (
    <div data-testid="property-list">
      {properties.map((property) => (
        <div
          key={property.id}
          data-testid={`property-card-${property.id}`}
          onClick={() => onSelect && onSelect(property)}
          style={{ cursor: 'pointer', border: '1px solid #ccc', padding: '10px', margin: '10px 0' }}
        >
          <h3>{property.title}</h3>
          <p>${property.price.toLocaleString()}</p>
          <p>{property.bedrooms} bedrooms</p>
          <p>{property.area} sq ft</p>
          <p>{property.city}</p>
        </div>
      ))}
    </div>
  );
};

export default PropertyList;
